    // MARK: - Template sentence generator (for words without hand-crafted sentences)

    static func templateSentences(for word: Word) -> [VocabSentence] {
        let w = word.spanish
        let e = word.english
        let templates: [(String, String, String)]  // (template, full, translation)
        switch word.partOfSpeech {
        case .noun:
            let isFem  = word.gender == "f"
            let art    = isFem ? "una" : "un"
            let artDef = isFem ? "la"  : "el"
            templates = [
                ("Necesito \(art) ___.", "Necesito \(art) \(w).", "I need a \(e)."),
                ("¿Dónde está \(artDef) ___?", "¿Dónde está \(artDef) \(w)?", "Where is the \(e)?"),
                ("Me gusta \(artDef) ___.", "Me gusta \(artDef) \(w).", "I like the \(e)."),
                ("Hay que conseguir \(art) ___.", "Hay que conseguir \(art) \(w).", "You have to get a \(e)."),
                ("Vi \(art) ___ en el mercado.", "Vi \(art) \(w) en el mercado.", "I saw a \(e) at the market."),
            ]
        case .adjective:
            templates = [
                ("Todo es muy ___.", "Todo es muy \(w).", "Everything is very \(e)."),
                ("Me siento ___.", "Me siento \(w).", "I feel \(e)."),
                ("Ese lugar es muy ___.", "Ese lugar es muy \(w).", "That place is very \(e)."),
                ("Ese trabajo es muy ___.", "Ese trabajo es muy \(w).", "That job is very \(e)."),
                ("¡Qué ___!", "¡Qué \(w)!", "How \(e)!"),
            ]
        case .adverb:
            let placeAdverbs: Set<String> = ["allí", "allá", "cerca", "lejos", "arriba", "abajo", "adelante", "atrás", "dentro", "fuera"]
            if placeAdverbs.contains(w) {
                templates = [
                    ("Espérame ___.", "Espérame \(w).", "Wait for me \(e)."),
                    ("Está ___ de aquí.", "Está \(w) de aquí.", "It's \(e) from here."),
                    ("Ponlo ___.", "Ponlo \(w).", "Put it \(e)."),
                ]
            } else {
                templates = [
                    ("___ hay que hacerlo.", "\(w.capitalized) hay que hacerlo.", "You have to do it \(e)."),
                    ("Lo hago ___.", "Lo hago \(w).", "I do it \(e)."),
                    ("Llegó ___.", "Llegó \(w).", "He arrived \(e)."),
                    ("___ lo entiendo.", "\(w.capitalized) lo entiendo.", "\(e.capitalized) I understand it."),
                    ("___ salgo de casa.", "\(w.capitalized) salgo de casa.", "I leave home \(e)."),
                ]
            }
        case .infinitive:
            templates = [
                ("Quiero ___ más.", "Quiero \(w) más.", "I want to \(e) more."),
                ("Tengo que ___ ahorita.", "Tengo que \(w) ahorita.", "I have to \(e) right now."),
                ("Me gusta ___ con mis amigos.", "Me gusta \(w) con mis amigos.", "I like to \(e) with my friends."),
                ("¿Puedes ___ eso?", "¿Puedes \(w) eso?", "Can you \(e) that?"),
                ("Hay que ___ para vivir bien.", "Hay que \(w) para vivir bien.", "You have to \(e) to live well."),
            ]
        case .preposition:
            templates = [
                ("Está justo ___ de aquí.", "Está justo \(w) de aquí.", "It's right \(e) here."),
                ("Lo hago ___ ti.", "Lo hago \(w) ti.", "I do it \(e) you."),
                ("Viene ___ el norte.", "Viene \(w) el norte.", "He comes \(e) the north."),
                ("Trabaja ___ las seis.", "Trabaja \(w) las seis.", "He works \(e) six."),
                ("Salió ___ la oficina.", "Salió \(w) la oficina.", "She went out \(e) the office."),
            ]
        case .conjunction:
            templates = [
                ("Fui, ___ llegué tarde.", "Fui, \(w) llegué tarde.", "I went, \(e) I arrived late."),
                ("Come ___ bebe lo que quieras.", "Come \(w) bebe lo que quieras.", "Eat \(e) drink what you want."),
                ("___ quieras, podemos ir.", "\(w.capitalized) quieras, podemos ir.", "\(e.capitalized) you want, we can go."),
                ("Es difícil, ___ posible.", "Es difícil, \(w) posible.", "It's difficult, \(e) possible."),
            ]
        case .pronoun:
            switch w {
            case "yo":
                templates = [
                    ("___ también quiero ir.", "Yo también quiero ir.", "I also want to go."),
                    ("___ vivo aquí.", "Yo vivo aquí.", "I live here."),
                    ("___ no lo sé.", "Yo no lo sé.", "I don't know."),
                ]
            case "tú":
                templates = [
                    ("¿___ eres de aquí?", "¿Tú eres de aquí?", "Are you from here?"),
                    ("___ también quieres ir.", "Tú también quieres ir.", "You also want to go."),
                    ("___ puedes hacerlo.", "Tú puedes hacerlo.", "You can do it."),
                ]
            case "él":
                templates = [
                    ("___ también quiere ir.", "Él también quiere ir.", "He also wants to go."),
